-- Remove all tasks, technicians, customers, messages tied to demo tenants
DELETE FROM tasks WHERE tenantId IN (SELECT id FROM tenants WHERE slug != 'nvc360');
DELETE FROM technicians WHERE tenantId IN (SELECT id FROM tenants WHERE slug != 'nvc360');
DELETE FROM customers WHERE tenantId IN (SELECT id FROM tenants WHERE slug != 'nvc360');
DELETE FROM messages WHERE tenantId IN (SELECT id FROM tenants WHERE slug != 'nvc360');
-- Remove demo tenant users
DELETE FROM users WHERE tenantId IN (SELECT id FROM tenants WHERE slug != 'nvc360');
-- Remove demo tenants
DELETE FROM tenants WHERE slug != 'nvc360';
-- Remove all demo users (seeded test accounts) except the super admin
DELETE FROM users WHERE email NOT IN ('admin@nvc360.com');

